            _context.Departments.Add(dept);
            _context.SaveChanges();

            var retrieved = _context.Departments.First();
            Assert.Equal("Physics", retrieved.Name);
            Assert.Equal(200000, retrieved.Budget);
        }

        [Fact]
        public void CanAddEnrollment_WithRelationships()
        {
            var student = new Student { FirstMidName = "A", LastName = "B", EnrollmentDate = DateTime.Now };
            _context.Students.Add(student);
            var dept = new Department { Name = "D", Budget = 1, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 6000, Title = "C", Credits = 1, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment { StudentID = student.ID, CourseID = course.CourseID, Grade = Grade.A };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .First();
            Assert.Equal("B", retrieved.Student.LastName);
            Assert.Equal("C", retrieved.Course.Title);
            Assert.Equal(Grade.A, retrieved.Grade);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            var instructor = new Instructor { FirstMidName = "I", LastName = "T", HireDate = DateTime.Now };
            _context.Instructors.Add(instructor);
            var dept = new Department { Name = "D", Budget = 1, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 7000, Title = "X", Credits = 1, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var ca = new CourseAssignment { CourseID = course.CourseID, InstructorID = instructor.ID };
            _context.CourseAssignments.Add(ca);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments.First();
            Assert.Equal(course.CourseID, retrieved.CourseID);
            Assert.Equal(instructor.ID, retrieved.InstructorID);
        }

        [Fact]
        public void OfficeAssignment_LinkedToInstructor()
        {
            var instructor = new Instructor { FirstMidName = "O", LastName = "A", HireDate = DateTime.Now };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var office = new OfficeAssignment { InstructorID = instructor.ID, Location = "Room 101" };
            _context.OfficeAssignments.Add(office);
            _context.SaveChanges();

            var retrieved = _context.OfficeAssignments.Include(o => o.Instructor).First();
            Assert.Equal("Room 101", retrieved.Location);
            Assert.Equal("A", retrieved.Instructor.LastName);
        }

        [Fact]
        public void CanAddNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };
            _context.Notifications.Add(notification);
            _context.SaveChanges();

            var retrieved = _context.Notifications.First();
            Assert.Equal("Student", retrieved.EntityType);
            Assert.Equal("CREATE", retrieved.Operation);
        }
    }
}

