using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var items = Enumerable.Range(1, 50).AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(1, page.PageIndex);
            Assert.Equal(5, page.TotalPages);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var items = Enumerable.Range(1, 50).AsQueryable();

            var page = PaginatedList<int>.Create(items, 2, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(11, page.First());
            Assert.Equal(20, page.Last());
        }

        [Fact]
        public void HasPreviousPage_False_ForFirstPage()
        {
            var items = Enumerable.Range(1, 50).AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.False(page.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_True_ForSecondPage()
        {
            var items = Enumerable.Range(1, 50).AsQueryable();

            var page = PaginatedList<int>.Create(items, 2, 10);

            Assert.True(page.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_True_WhenMorePagesExist()
        {
            var items = Enumerable.Range(1, 50).AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.True(page.HasNextPage);
        }

        [Fact]
        public void HasNextPage_False_OnLastPage()
        {
            var items = Enumerable.Range(1, 50).AsQueryable();

            var page = PaginatedList<int>.Create(items, 5, 10);

            Assert.False(page.HasNextPage);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly_WithRemainder()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.Equal(3, page.TotalPages);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly_EvenDivision()
        {
            var items = Enumerable.Range(1, 20).AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.Equal(2, page.TotalPages);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyPage()
        {
            var items = Enumerable.Empty<int>().AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.Empty(page);
            Assert.Equal(0, page.TotalPages);
        }

        [Fact]
        public void Create_SingleItem_ReturnsOnePage()
        {
            var items = new[] { 42 }.AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.Single(page);
            Assert.Equal(1, page.TotalPages);
            Assert.False(page.HasNextPage);
            Assert.False(page.HasPreviousPage);
        }
    }

