using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var items = Enumerable.Range(1, 50).AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(1, page.PageIndex);
            Assert.Equal(5, page.TotalPages);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var items = Enumerable.Range(1, 50).AsQueryable();

            var page = PaginatedList<int>.Create(items, 2, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(11, page.First());
            Assert.Equal(20, page.Last());
        }

        [Fact]
        public void HasPreviousPage_False_ForFirstPage()
        {
            var items = Enumerable.Range(1, 50).AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.False(page.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_True_ForSecondPage()
        {
            var items = Enumerable.Range(1, 50).AsQueryable();

            var page = PaginatedList<int>.Create(items, 2, 10);

            Assert.True(page.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_True_WhenMorePagesExist()
        {
            var items = Enumerable.Range(1, 50).AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.True(page.HasNextPage);
        }

        [Fact]
        public void HasNextPage_False_OnLastPage()
        {
            var items = Enumerable.Range(1, 50).AsQueryable();

            var page = PaginatedList<int>.Create(items, 5, 10);

            Assert.False(page.HasNextPage);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly_WithRemainder()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.Equal(3, page.TotalPages);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly_EvenDivision()
        {
            var items = Enumerable.Range(1, 20).AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.Equal(2, page.TotalPages);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyPage()
        {
            var items = Enumerable.Empty<int>().AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.Empty(page);
            Assert.Equal(0, page.TotalPages);
        }

        [Fact]
        public void Create_SingleItem_ReturnsOnePage()
        {
            var items = new[] { 42 }.AsQueryable();

            var page = PaginatedList<int>.Create(items, 1, 10);

            Assert.Single(page);
            Assert.Equal(1, page.TotalPages);
            Assert.False(page.HasNextPage);
            Assert.False(page.HasPreviousPage);
        }
    }

    public class PersonModelTests
    {
        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student { FirstMidName = "John", LastName = "Doe" };

            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void Instructor_FullName_ReturnsCorrectFormat()
        {
            var instructor = new Instructor { FirstMidName = "Jane", LastName = "Smith" };

            Assert.Equal("Smith, Jane", instructor.FullName);
        }
    }

    public class EnrollmentModelTests
    {
        [Fact]
        public void Grade_CanBeNull()
        {
            var enrollment = new Enrollment { CourseID = 1, StudentID = 1 };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Grade_CanBeSet()
        {
            var enrollment = new Enrollment { CourseID = 1, StudentID = 1, Grade = Grade.B };

            Assert.Equal(Grade.B, enrollment.Grade);
        }
    }

    public class DepartmentModelTests
    {
        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Science",
                Budget = 500000,
                StartDate = DateTime.Parse("2020-01-01"),
                InstructorID = 5
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Science", dept.Name);
            Assert.Equal(500000, dept.Budget);
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_CanBeNull()
        {
            var dept = new Department { Name = "Test", Budget = 0, StartDate = DateTime.Now };

            Assert.Null(dept.InstructorID);
        }
    }

    public class CourseModelTests
    {
        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 2,
                TeachingMaterialImagePath = "/img/chem.png"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(2, course.DepartmentID);
            Assert.Equal("/img/chem.png", course.TeachingMaterialImagePath);
        }
    }

    public class NotificationModelTests
    {
        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var n = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "10",
                Operation = "CREATE",
                Message = "New student",
                CreatedAt = DateTime.Now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, n.Id);
            Assert.Equal("Student", n.EntityType);
            Assert.False(n.IsRead);
            Assert.Null(n.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }
    }
}

